import{_ as t,o as i,c as o,ag as a}from"./chunks/framework.Ca42NP5A.js";const u=JSON.parse('{"title":"Attestation type conventions","description":"","frontmatter":{},"headers":[],"relativePath":"reference/attestation-types.md","filePath":"reference/attestation-types.md","lastUpdated":null}'),n={name:"reference/attestation-types.md"};function r(d,e,s,l,c,p){return i(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="attestation-type-conventions" tabindex="-1">Attestation type conventions <a class="header-anchor" href="#attestation-type-conventions" aria-label="Permalink to &quot;Attestation type conventions&quot;">​</a></h1><p>The contract&#39;s <code>type</code> field is free-text. Consistent prefixes make attestations interoperable, filterable, and interpretable.</p><h2 id="standard-prefixes" tabindex="-1">Standard prefixes <a class="header-anchor" href="#standard-prefixes" aria-label="Permalink to &quot;Standard prefixes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prefix</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>skill:</code></td><td>Verified competency in a specific skill</td><td><code>skill:literature-review-v2</code></td></tr><tr><td><code>diploma:</code></td><td>Completion of a formal program</td><td><code>diploma:mit-cs-2026</code></td></tr><tr><td><code>license:</code></td><td>Authorization to operate in a regulated domain</td><td><code>license:medical-advice-v1</code></td></tr><tr><td><code>audit:</code></td><td>Behavioral review passed in a specific period</td><td><code>audit:safety-review-2026q1</code></td></tr><tr><td><code>identity:</code></td><td>Identity claim tying agent to a concrete system</td><td><code>identity:anthropic-claude-sonnet-4-6</code></td></tr><tr><td><code>badge:</code></td><td>Community recognition, non-verifying</td><td><code>badge:early-adopter</code></td></tr><tr><td><code>membership:</code></td><td>Confirmed membership in an organization</td><td><code>membership:acme-dao</code></td></tr></tbody></table><h2 id="naming-conventions-within-a-prefix" tabindex="-1">Naming conventions within a prefix <a class="header-anchor" href="#naming-conventions-within-a-prefix" aria-label="Permalink to &quot;Naming conventions within a prefix&quot;">​</a></h2><ul><li>Lowercase, hyphens for spaces, no whitespace</li><li>Version when meaningful: <code>skill:literature-review-v2</code> makes the version explicit</li><li>Date-stamp when period-scoped: <code>audit:safety-2026q1</code> makes the review period clear</li><li>Provider-specific identity: <code>identity:&lt;provider&gt;-&lt;model&gt;-&lt;version&gt;</code></li></ul><h2 id="how-to-propose-a-new-prefix" tabindex="-1">How to propose a new prefix <a class="header-anchor" href="#how-to-propose-a-new-prefix" aria-label="Permalink to &quot;How to propose a new prefix&quot;">​</a></h2><p>Open a <a href="https://github.com/rsilvestre/agent-birth-certificate/discussions/categories/ideas" target="_blank" rel="noreferrer">GitHub Discussion</a> describing:</p><ol><li>The proposed prefix and meaning</li><li>Who would issue attestations of this type</li><li>How consumers would use them</li><li>An example</li></ol><p>If consensus forms, submit a PR adding it to this table. See <a href="/docs/contributing">contributing</a>.</p><h2 id="guidance-for-issuers" tabindex="-1">Guidance for issuers <a class="header-anchor" href="#guidance-for-issuers" aria-label="Permalink to &quot;Guidance for issuers&quot;">​</a></h2><p>A good attestation answers three questions in its <code>description</code>:</p><ol><li><strong>What specifically was verified?</strong></li><li><strong>How was it verified?</strong></li><li><strong>When / under what conditions?</strong></li></ol><h3 id="weak-description" tabindex="-1">Weak description <a class="header-anchor" href="#weak-description" aria-label="Permalink to &quot;Weak description&quot;">​</a></h3><blockquote><p>Good at code review</p></blockquote><h3 id="strong-description" tabindex="-1">Strong description <a class="header-anchor" href="#strong-description" aria-label="Permalink to &quot;Strong description&quot;">​</a></h3><blockquote><p>Passed the SecureCode-2025 benchmark at 91% (top decile). Verified 2026-03-15 against commit sha abc123 of the agent&#39;s model config. Full report: ipfs://bafkrei...</p></blockquote><h2 id="guidance-for-consumers" tabindex="-1">Guidance for consumers <a class="header-anchor" href="#guidance-for-consumers" aria-label="Permalink to &quot;Guidance for consumers&quot;">​</a></h2><p>Attestations are claims, not guarantees. Trust depends on:</p><ol><li><strong>Who issued it</strong> — check the issuer wallet and its reputation</li><li><strong>What evidence it references</strong> — the <code>uri</code> field should point to verifiable detail</li><li><strong>Whether it&#39;s been revoked</strong> — check <code>revoked</code> flag</li><li><strong>How the issuer votes with their track record</strong> — selective issuers accumulate trust; spammy ones lose it</li></ol><p>For high-stakes decisions, prefer attestations from a small whitelist of known reputable issuers.</p><h2 id="provider-specific-conventions-community-maintained" tabindex="-1">Provider-specific conventions (community maintained) <a class="header-anchor" href="#provider-specific-conventions-community-maintained" aria-label="Permalink to &quot;Provider-specific conventions (community maintained)&quot;">​</a></h2><p>As the ecosystem grows, specific providers and communities adopt conventions. Pull requests welcome.</p><h3 id="ai-model-identity" tabindex="-1">AI model identity <a class="header-anchor" href="#ai-model-identity" aria-label="Permalink to &quot;AI model identity&quot;">​</a></h3><p>Suggested format: <code>identity:&lt;provider&gt;-&lt;model-name&gt;-&lt;version&gt;</code></p><p>Examples:</p><ul><li><code>identity:anthropic-claude-sonnet-4-6</code></li><li><code>identity:openai-gpt-5</code></li><li><code>identity:meta-llama-3-70b-instruct</code></li><li><code>identity:google-gemini-2-ultra</code></li><li><code>identity:custom-&lt;org&gt;-&lt;model&gt;</code> for fine-tuned / custom models</li></ul><h3 id="skill-taxonomy-evolving" tabindex="-1">Skill taxonomy (evolving) <a class="header-anchor" href="#skill-taxonomy-evolving" aria-label="Permalink to &quot;Skill taxonomy (evolving)&quot;">​</a></h3><ul><li><code>skill:code-generation-v&lt;N&gt;</code></li><li><code>skill:code-review-v&lt;N&gt;</code></li><li><code>skill:literature-review-v&lt;N&gt;</code></li><li><code>skill:translation-&lt;lang-from&gt;-to-&lt;lang-to&gt;</code></li><li><code>skill:legal-research-&lt;jurisdiction&gt;</code></li><li><code>skill:medical-triage-&lt;specialty&gt;</code></li></ul><h3 id="audit-types" tabindex="-1">Audit types <a class="header-anchor" href="#audit-types" aria-label="Permalink to &quot;Audit types&quot;">​</a></h3><ul><li><code>audit:safety-&lt;period&gt;</code> — general AI safety</li><li><code>audit:alignment-&lt;period&gt;</code> — alignment review</li><li><code>audit:compliance-&lt;standard&gt;-&lt;period&gt;</code> — e.g., <code>audit:compliance-iso-27001-2026q1</code></li></ul><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/docs/concepts/attestations">Concepts: Attestations and trust</a> — why this works</li><li><a href="/docs/guides/issue-attestation">Guide: Issue an attestation</a> — CLI walkthrough</li><li><a href="/docs/contributing">Contributing</a> — propose additions</li></ul>',33)])])}const m=t(n,[["render",r]]);export{u as __pageData,m as default};
